<span class="line">    <span class="token punctuation">-</span> <span class="token key atrule">group</span><span class="token punctuation">:</span> <span class="token string">&quot;&quot;</span>            <span class="token comment"># core API group (Pods, Services, ConfigMaps, etc.)</span></span>
